-- 172: Reseed the studio-sitter lock-up template (jon feedback round)
--
-- Follow-up tweaks after the live trial (see 171 for the first real port):
--   * "Lights off & lock up" section — all lights-off items moved to the end,
--     front door LAST;
--   * note_prompt on "clients paid" + "kitchen replenished" — an always-on
--     optional note box (how they paid / what supplies are needed), regardless
--     of the yes/no answer.
--
-- Generated from services/studio-sitter-lockup.ts DEFAULT_TEMPLATE so the DB
-- seed and code fallback stay identical. Overwrites unconditionally (171 could
-- already have applied); Settings tweaks are re-applied there afterwards.

UPDATE system_settings
   SET value = '{"version":1,"intro":"Quick walk round before you lock up. Flag anything that isn''t right — we''d rather know tonight than find out tomorrow.","items":[{"id":"clients_out_on_time","section":"Upstairs","label":"Were the clients out on time? (if not, note how late & why below)","type":"yesno","expected":"yes"},{"id":"clients_paid","section":"Upstairs","label":"Have the clients paid? (if so, note how below and put the card receipt in the till)","type":"yesno","expected":"yes","note_prompt":"How did they pay / what’s outstanding? (and pop the card receipt in the till)"},{"id":"pas_amps_powered_down","section":"Upstairs","label":"PAs, amps, client equipment / pedals etc powered down","type":"yesno","expected":"yes"},{"id":"litter_cleared","section":"Upstairs","label":"Cups / glasses / plates cleared away, all litter collected and bin bag changed","type":"yesno","expected":"yes"},{"id":"crockery_washed","section":"Upstairs","label":"All cups / crockery washed or loaded into the downstairs dishwasher","type":"yesno","expected":"yes"},{"id":"kitchen_replenished","section":"Upstairs","label":"Studio kitchens replenished for the morning (cups, plates, cutlery, kitchen roll, tea, coffee — note below if milk etc needed)","type":"yesno","expected":"yes","note_prompt":"Anything running low? (milk, coffee, kitchen roll, etc.)"},{"id":"toilets_stocked","section":"Upstairs","label":"Toilets clean, with soap and toilet paper","type":"yesno","expected":"yes"},{"id":"upstairs_double_door","section":"Upstairs","label":"Upstairs double door locked and bolted","type":"yesno","expected":"yes"},{"id":"kitchen_toilet_windows","section":"Upstairs","label":"Kitchen and toilet windows closed","type":"yesno","expected":"yes"},{"id":"ac_off","section":"Upstairs","label":"All AC turned off","type":"yesno","expected":"yes"},{"id":"side_fire_exit_closed","section":"Upstairs","label":"Side fire exit at the bottom of the stairs closed","type":"yesno","expected":"yes"},{"id":"rooms_vacuumed_bins","section":"Upstairs","label":"Rooms clean, vacuumed and bins emptied / new bin bag","type":"yesno","expected":"yes","end_of_booking_only":true},{"id":"hired_kit_boxed","section":"Upstairs","label":"All studio-hired mics, cables, 4-ways, DIs etc coiled, taped and put away in the box","type":"yesno","expected":"yes","end_of_booking_only":true},{"id":"backline_stored","section":"Upstairs","label":"Ooosh backline packed away and stored (shelves in the upstairs kitchen, or by the double doors / downstairs if from the warehouse)","type":"yesno","expected":"yes","end_of_booking_only":true,"reference":{"text":"When the booking has ended, the rooms should be reset and gear stored like this:","photos":["https://www.jotform.com/uploads/jonwood/form_files/IMG_3638.65b7945e03a2e5.97895687.jpg","https://www.jotform.com/uploads/jonwood/form_files/IMG_2315.64f9b25b0a0af6.19275184.jpg","https://www.jotform.com/uploads/jonwood/form_files/IMG_3635.65b795cd3a8a08.69909573.jpg"]}},{"id":"computer_stereo_off","section":"Downstairs","label":"Computer, stereo and printer turned off","type":"yesno","expected":"yes"},{"id":"dishwasher_on","section":"Downstairs","label":"Dishwasher loaded with cups / plates from upstairs and down, tablet in, switched on","type":"yesno","expected":"yes"},{"id":"front_desk_tidy","section":"Downstairs","label":"Front desk clear and tidy","type":"yesno","expected":"yes"},{"id":"lift_returned","section":"Downstairs","label":"Lift returned to ground level and switched off","type":"yesno","expected":"yes"},{"id":"thermostat_down","section":"Downstairs","label":"Downstairs thermostat turned down to 10","type":"yesno","expected":"yes"},{"id":"rear_fire_exit","section":"Downstairs","label":"Rear fire exit door checked","type":"yesno","expected":"yes"},{"id":"outside_containers_locked","section":"Downstairs","label":"Outside containers closed and locked","type":"yesno","expected":"yes"},{"id":"cupboard_gates_locked","section":"Downstairs","label":"Outdoor cupboard and both gates locked","type":"yesno","expected":"yes"},{"id":"vans_locked","section":"Downstairs","label":"All vans locked, nothing left outside","type":"yesno","expected":"yes"},{"id":"van_keys_safe","section":"Downstairs","label":"All van keys in the safe and the safe locked","type":"yesno","expected":"yes"},{"id":"room_lights_off","section":"Lights off & lock up","label":"Room lights + LEDs off","type":"yesno","expected":"yes"},{"id":"kitchen_hall_lights_off","section":"Lights off & lock up","label":"Kitchen, toilet and hallway / stairs lights off","type":"yesno","expected":"yes"},{"id":"foyer_light_off","section":"Lights off & lock up","label":"Foyer light off","type":"yesno","expected":"yes"},{"id":"stockroom_lights_off","section":"Lights off & lock up","label":"Stockroom lights off","type":"yesno","expected":"yes"},{"id":"downstairs_lights_off","section":"Lights off & lock up","label":"Downstairs lights off","type":"yesno","expected":"yes"},{"id":"front_door_locked","section":"Lights off & lock up","label":"Front door padlocked and locked, key placed in the outside key cupboard","type":"yesno","expected":"yes"}],"notes_label":"Anything we need to know? Money owed, items taken, jobs for tomorrow, anything left undone.","lost_property_prompt":"Found something a band left behind? Log it here so we can get it back to them."}',
       label = 'Lock-up report template',
       updated_at = NOW()
 WHERE key = 'studio_sitter_lockup_template';
